import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input being passed as a parameter
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize and encode the user input using OWASP Java Encoder
        String sanitizedInput = Encode.forHtml(userInput);

        // Properly handling user input by sanitizing and encoding it
        String output = "Welcome, " + sanitizedInput;

        // Printing the output
        System.out.println(output);
    }
}

